    def compute(
        self,
        query=None,
        expected_ids=None,
        retrieved_ids=None,
        expected_texts=None,
        retrieved_texts=None,
        relevance_scores=None,
        **kwargs,
    ):
        if (retrieved_ids is None or expected_ids is None or not retrieved_ids or not expected_ids):
            raise ValueError(...)
        mode = self.mode
        expected_set = set(expected_ids)

        def get_relevance(docid):
            if docid not in expected_set:
                return 0.0
            if relevance_scores is not None:
                return relevance_scores.get(docid, 1.0)
            return 1.0

        dcg = sum(discounted_gain(rel=get_relevance(docid), i=i, mode=mode) for i, docid in enumerate(retrieved_ids, start=1))

        if relevance_scores is not None:
            ideal_rels = sorted((relevance_scores.get(eid, 1.0) for eid in expected_ids), reverse=True)
        else:
            ideal_rels = [1.0] * len(expected_ids)
        idcg = sum(discounted_gain(rel=rel, i=i, mode=mode) for i, rel in enumerate(ideal_rels, start=1))

        if idcg == 0:
            return RetrievalMetricResult(score=0.0)
        return RetrievalMetricResult(score=dcg / idcg)

Note idcg is now over len(expected_ids) items (your fix), not min(len(retrieved_ids), len(expected_ids)). I'll apply this now — reply ACCEPT if this looks right, or REVISE if you want changes."

